mapper.select:
select a.id,goods.id goodsId,goods.imgurl,goods.product_title,goods.initial,b.id acId from lkt_group_goods a inner join lkt_group_activity b on a.activity_id=b.id and a.recycle=0 left join lkt_product_list goods on goods.id=a.goods_id
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

mapper.sql:
and a.gongyingshang=''
and a.is_presell = 0
and a.num > 0
and a.store_id = #{store_id}
and a.mch_id = #{mchId}

    and a.recycle = #{recycle} 
    and a.recycle = 0


    
        #{id,jdbcType=INTEGER}
    

and a.status = #{goods_status}
and a.commodity_type = #{commodity_type}
AND a.product_class like CONCAT('%-',
    #{classId},'-%')
and a.brand_id = #{goodsBrandId}
and a.product_title like concat('%', #{goodsName},'%')
and (a.product_title like concat('%', #{key},'%') or a.id =#{key})
and EXISTS(select x.id from lkt_group_goods x where a.id=x.goods_id and x.recycle=0)
and EXISTS(select x.id from lkt_group_goods x where a.id=x.goods_id and x.recycle=0 and x.activity_id =#{activityId})
and not EXISTS(select x.id from lkt_group_goods x where a.id=x.goods_id and x.recycle=0 and x.activity_id =#{not_activityId})

    
        #{id,jdbcType=INTEGER}

mapper.select:
select a.id,a.product_title goodsName,a.imgurl,a.num stockNum,cls.pname className,brand.brand_name from lkt_product_list a left join lkt_product_class cls on cls.cid= substring_index(substring_index(a.product_class, '-', -2), '-', 1) left join lkt_brand_class brand on brand.brand_id= a.brand_id
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

SELECT a.groupGoodsId, a.goodsId, a.product_title, a.imgurl, a.weight, a.openId, a.team_num, a.attr_id, a.teamStatus, a.teamUserId, a.acId, a.freight, a.mch_id, a.goodsStatus, a.attribute, a.attrId, a.attrImg, a.content, a.status, a.start_date, a.end_date, a.openEndDate, a.team_limit, a.team_rule, a.stockNum, a.mchName, a.mchImg, a.is_open, a.business_hours, a.headimgurl, a.user_name, a.video, a.pro_video FROM ( SELECT a.id groupGoodsId, a.goods_id goodsId, b.product_title, b.imgurl, b.weight, op.id openId, op.team_num, op.attr_id, op.STATUS teamStatus, op.user_id teamUserId, ac.id acId, b.freight, b.mch_id, b.STATUS goodsStatus, attr.attribute, attr.id attrId, attr.img attrImg, b.content, ac.STATUS, ac.start_date, ac.end_date, op.end_date openEndDate, ac.team_limit, ac.team_rule, b.num stockNum, mch.NAME mchName, mch.head_img mchImg, mch.is_open, mch.business_hours, `user`.headimgurl, `user`.user_name, b.video, b.pro_video, ROW_NUMBER() over(partition by a.id) as top FROM lkt_group_goods a INNER JOIN lkt_group_activity ac ON ac.id = a.activity_id INNER JOIN lkt_product_list b ON a.goods_id = b.id INNER JOIN lkt_configure attr ON attr.pid = b.id AND attr.recycle = b.recycle LEFT JOIN lkt_group_open op ON op.activity_id = ac.id AND op.goods_id = a.goods_id AND op.recycle = 0 LEFT JOIN lkt_user `user` ON `user`.user_id = op.user_id LEFT JOIN lkt_mch mch ON mch.id = b.mch_id
a.add_date ${add_time_sort},
) AS a WHERE a.top = 1 limit #{pageStart},#{pageEnd}

